;; ProjectName SDK EntityName entity (generated by @voxgig/sdkgen).
(ns sdk.entity.entityname
  (:refer-clojure :exclude [load list remove update])
  (:require [sdk.core :as core]
            [voxgig.struct :as vs]))

(declare new-entity)

(defn- ensure-entopts [entopts]
  (let [e (if (vs/ismap entopts) entopts (vs/jm))]
    (when (nil? (vs/getprop e "active")) (.put ^java.util.Map e "active" true))
    e))

(defn- ent-data-set [ent args]
  (when args
    (reset! (:_data ent) (let [m (core/to-map (vs/clone args))] (if m m (vs/jm))))
    (core/feature-hook (:_entctx ent) "SetData")))

(defn- ent-data-get [ent]
  (core/feature-hook (:_entctx ent) "GetData")
  (vs/clone (deref (:_data ent))))

(defn- ent-match-set [ent args]
  (when args
    (reset! (:_match ent) (let [m (core/to-map (vs/clone args))] (if m m (vs/jm))))
    (core/feature-hook (:_entctx ent) "SetMatch")))

(defn- ent-match-get [ent]
  (core/feature-hook (:_entctx ent) "GetMatch")
  (vs/clone (deref (:_match ent))))

(defn- new-entity [client entopts]
  (let [entopts (ensure-entopts entopts)
        utility (core/get-utility client)
        data (atom (vs/jm))
        match (atom (vs/jm))
        entctx (core/make-context (vs/jm "entopts" entopts) (core/client-root-ctx client))
        ent {:_name "entityname" :_client client :_utility utility :_entopts entopts
             :_data data :_match match :_entctx entctx
             :get-name (fn [] "entityname")
             :make (fn [] (new-entity client (vs/clone entopts)))}
        ent (assoc ent
                   :data-set (fn [args] (ent-data-set ent args))
                   :data-get (fn [] (ent-data-get ent))
                   :match-set (fn [args] (ent-match-set ent args))
                   :match-get (fn [] (ent-match-get ent)))]
    (core/oset! entctx :entity ent)
    (core/feature-hook entctx "PostConstructEntity")
    ent))

;; Canonical facade: (EntityName client data) accessor delegates here.
(defn make [client data] (new-entity client data))

;; The operation pipeline runner. Feature hooks fire at each stage; a stage
;; error is surfaced via make-error (which raises, or returns the bare result
;; when throwing is disabled). The hook marker lines below are rewritten to
;; (core/feature-hook ctx "<Stage>") by the component's hook regex — a `;`
;; comment form, since jostraca's built-in tag replacement only matches `//`.
(defn- run-op [ctx post-done]
  (try
    ; #PrePoint-Hook
    (let [[point err] ((core/uget ctx :make-point) ctx)]
      (core/out-set! ctx "point" point)
      (if err
        ((core/uget ctx :make-error) ctx err)
        (do
          ; #PreSpec-Hook
          (let [[spec err] ((core/uget ctx :make-spec) ctx)]
            (core/out-set! ctx "spec" spec)
            (if err
              ((core/uget ctx :make-error) ctx err)
              (do
                ; #PreRequest-Hook
                (let [[resp err] ((core/uget ctx :make-request) ctx)]
                  (core/out-set! ctx "request" resp)
                  (if err
                    ((core/uget ctx :make-error) ctx err)
                    (do
                      ; #PreResponse-Hook
                      (let [[resp2 err] ((core/uget ctx :make-response) ctx)]
                        (core/out-set! ctx "response" resp2)
                        (if err
                          ((core/uget ctx :make-error) ctx err)
                          (do
                            ; #PreResult-Hook
                            (let [[result err] ((core/uget ctx :make-result) ctx)]
                              (core/out-set! ctx "result" result)
                              (if err
                                ((core/uget ctx :make-error) ctx err)
                                (do
                                  ; #PreDone-Hook
                                  (post-done)
                                  ((core/uget ctx :done) ctx))))))))))))))))
    (catch Throwable operr
      ; #PreUnexpected-Hook
      (throw operr))))

;; Streaming operation. Runs `action` (an op name, e.g. "list") through the
;; full pipeline and returns a LAZY SEQUENCE of result items, so the
;; `streaming` feature's incremental output is reachable (a normal op call
;; materialises the whole result). When the streaming feature is active the
;; result carries a `stream` thunk and this yields from it (honouring
;; chunkSize); otherwise it falls back to the materialised items, so stream
;; always yields. Records are unwrapped to bare struct maps (matching list).
;; `callopts` parameterises the call:
;;   - ctrl:   per-call pipeline control (threaded onto the op ctx);
;;   - body:   an async-iterable/list payload for outbound (upload) streaming,
;;             attached to the request (reqdata.body$ + a stream-out marker);
;;   - signal: an optional 0-arg fn; when it returns true iteration stops.
(defn stream [ent action args callopts]
  (let [callopts (let [m (core/to-map callopts)] (if m m (vs/jm)))
        ctrl (let [c (core/to-map (vs/getprop callopts "ctrl"))] (if c c (vs/jm)))
        _ (.put ^java.util.Map ctrl "stream" callopts)
        ctxmap (vs/jm "opname" action "ctrl" ctrl
                      "match" (deref (:_match ent)) "data" (deref (:_data ent)))
        _ (when-let [am (core/to-map args)]
            (doseq [item (or (vs/items am) [])]
              (.put ^java.util.Map ctxmap (vs/getprop item 0) (vs/getprop item 1))))
        ctx (core/make-context ctxmap (:_entctx ent))]
    ;; Outbound: expose an async-iterable/list payload so the request builder /
    ;; transport can stream it as the request body.
    (when-let [body (vs/getprop callopts "body")]
      (let [reqdata (let [r (core/to-map (core/oget ctx :reqdata))] (if r r (vs/jm)))]
        (.put ^java.util.Map reqdata "body$" body)
        (core/oset! ctx :reqdata reqdata)
        (core/oset! ctx :stream-out body)))
    (run-op ctx (fn []))
    (let [result (core/oget ctx :result)
          signal (vs/getprop callopts "signal")
          signalled? (fn [] (and (fn? signal) (boolean (signal))))
          unwrap (fn unwrap [item]
                   (cond
                     (nil? item) item
                     (and (map? item) (:data-get item)) ((:data-get item))
                     (vs/islist item) (mapv unwrap (vec item))
                     :else item))
          ;; Inbound: prefer the streaming feature's iterator; else fall back
          ;; to the materialised items so stream always yields.
          raw (if (and result (fn? (core/oget result :stream)))
                (vec ((core/oget result :stream)))
                (let [rd (when result (core/oget result :resdata))]
                  (cond (vs/islist rd) (vec rd) (nil? rd) [] :else [rd])))
          items (mapv unwrap raw)]
      ;; A lazy sequence that checks `signal` between yields.
      (letfn [(lz [xs] (lazy-seq
                         (when (and (seq xs) (not (signalled?)))
                           (cons (first xs) (lz (rest xs))))))]
        (lz items)))))

